.darma-loader-darma-custom-708 {
  color: var(--loader-color, #f97316);
width: 40px;
height: 26px;
--c:no-repeat linear-gradient(currentColor 0 0);
background:
var(--c) 0 100%,
var(--c) 50% 100%,
var(--c) 100% 100%;
background-size:8px calc(100% - 4px);
position: relative;
}
.darma-loader-darma-custom-708:before {
content: "";
position: absolute;
width: 8px;
height: 8px;
border-radius: 50%;
background: currentColor;
left: 0;
top: 0;
animation:
darma-loader-darma-custom-708-l3-1 1.5s linear infinite alternate,
darma-loader-darma-custom-708-l3-2 0.75s cubic-bezier(.45, 0, .55, 1) infinite;
}
@keyframes darma-loader-darma-custom-708-l3-1 {
100% {left:calc(100% - 8px)}
}
@keyframes darma-loader-darma-custom-708-l3-2 {
100% {top:-0.1px}
}

